# Copyright Sierra
"""Shared Amazon Connect Lambda for Sierra PSTN and EVT transfer data flows."""

import json
import logging
import os
import re
import time
from typing import Any
from urllib.parse import quote

import urllib3

logger = logging.getLogger()
logger.setLevel(logging.INFO)

AGENT_TOKEN = os.environ["SIERRA_AGENT_TOKEN"]
TRANSFER_DATA_API_TOKEN = os.environ["SIERRA_TRANSFER_DATA_API_TOKEN"]
SIERRA_API_BASE = os.environ.get("SIERRA_API_BASE", "https://api.sierra.chat")
SIERRA_PHONE_NUMBER = os.environ.get("SIERRA_PHONE_NUMBER", "")
SIERRA_VOICE_CONNECTOR_ARN = os.environ.get("SIERRA_VOICE_CONNECTOR_ARN", "")
SIERRA_SIP_USERNAME = os.environ.get("SIERRA_SIP_USERNAME", "sierra")
SIERRA_SIP_FROM_USER = os.environ.get("SIERRA_SIP_FROM_USER", "amazon-connect")
SIERRA_TRANSFER_MODE = os.environ.get("SIERRA_TRANSFER_MODE", "").strip().lower()
SIERRA_TRANSFER_METHOD = os.environ.get("SIERRA_TRANSFER_METHOD", "").strip()
INTEGRATION_VERSION = os.environ.get("SIERRA_INTEGRATION_VERSION", "unknown")
TRACE_MODULE_ID = os.environ.get("SIERRA_INTEGRATION_MODULE_ID", "").strip()

TRANSFER_DATA_API_KEYS_URL = f"{SIERRA_API_BASE}/telephony/transfer-data/keys/{AGENT_TOKEN}"
TRANSFER_DATA_API_URL = f"{SIERRA_API_BASE}/telephony/transfer-data/{AGENT_TOKEN}"
TRANSFER_DATA_COMPATIBILITY_DATE = "2026-05-18"
OUTBOUND_DATA_POLL_BUDGET_SECONDS = 6.5

ERROR_TRANSFER_DATA_API = "transfer_data_api_error"
ERROR_TRANSFER_DATA_EXCEPTION = "transfer_data_exception"
ERROR_TRANSFER_DATA_AGENT_IN_PROGRESS = "transfer_data_agent_in_progress"
ERROR_TRANSFER_DATA_AGENT_NOT_STARTED = "transfer_data_agent_not_started"
ERROR_TRANSFER_DATA_NOT_FOUND = "transfer_data_not_found"
ERROR_TRANSFER_DATA_NOT_PRODUCED = "transfer_data_not_produced"
ERROR_TRANSFER_DATA_NOT_READY = "transfer_data_not_ready"
ERROR_TRANSFER_DATA_PARSE = "transfer_data_parse_error"
ERROR_MISSING_CONTACT_ID = "missing_contact_id"
ERROR_MISSING_CONFIGURATION = "missing_configuration"
ERROR_MISSING_OUTBOUND_KEY = "missing_outbound_key"
ERROR_UNKNOWN_OPERATION = "unknown_operation"
ERROR_UNHANDLED_EXCEPTION = "unhandled_lambda_exception"

_http = urllib3.PoolManager()


def _mode(parameters: dict[str, Any] | None = None) -> str:
    params = parameters or {}
    explicit = str(params.get("sierraTransferMode") or SIERRA_TRANSFER_MODE or "").strip().lower()
    if explicit in ("evt", "external_voice_transfer", "external-voice-transfer"):
        return "evt"
    if explicit in ("pstn", "phone"):
        return "pstn"
    if str(params.get("VoiceConnectorArn") or SIERRA_VOICE_CONNECTOR_ARN).strip():
        return "evt"
    return "pstn"


def _transfer_method(parameters: dict[str, Any] | None = None) -> str:
    params = parameters or {}
    return str(params.get("sierraTransferMethod") or SIERRA_TRANSFER_METHOD or "").strip()


def _trace_module_id(mode: str) -> str:
    if TRACE_MODULE_ID:
        return TRACE_MODULE_ID
    if mode == "evt":
        return "@sierra/integrations-builtin/amazon-connect-voice-evt"
    return "@sierra/integrations-builtin/amazon-connect-voice-pstn"


def _ttl_seconds(mode: str) -> int:
    raw = os.environ.get("SIERRA_TRANSFER_DATA_TTL_SECONDS", "").strip()
    if raw:
        try:
            return max(1, int(raw))
        except ValueError:
            logger.warning("Invalid SIERRA_TRANSFER_DATA_TTL_SECONDS=%s", raw)
    return 3600 if mode == "evt" else 60


def _auth_headers(
    xray_trace_id: str | None = None,
    content_type: str | None = None,
    telemetry_events: list[dict[str, Any]] | None = None,
    mode: str = "pstn",
) -> dict[str, str]:
    headers = {"Authorization": f"Bearer {TRANSFER_DATA_API_TOKEN}"}
    if content_type:
        headers["Content-Type"] = content_type
    if xray_trace_id:
        headers["X-Amzn-Trace-Id"] = xray_trace_id
    if telemetry_events:
        headers["X-Sierra-Telemetry-Module-Id"] = _trace_module_id(mode)
        headers["X-Sierra-Telemetry-Events"] = json.dumps(telemetry_events, separators=(",", ":"))
    return headers


def _failure(
    error: str,
    error_code: str,
    status_code: int | None = None,
    telemetry_accepted: bool = False,
) -> dict[str, Any]:
    result: dict[str, Any] = {"success": False, "error": error, "error_code": error_code}
    if status_code is not None:
        result["status_code"] = status_code
    if telemetry_accepted:
        result["telemetry_accepted"] = True
    return result


def _connect_failure_response(result: dict[str, Any]) -> dict[str, str]:
    response = {
        "success": "false",
        "error": str(result.get("error", "")),
        "errorCode": str(result.get("error_code", "")),
    }
    if result.get("status_code") is not None:
        response["statusCode"] = str(result["status_code"])
    return response


def _telemetry_accepted(response: Any) -> bool:
    return str(response.headers.get("X-Sierra-Telemetry-Accepted", "")).lower() == "true"


def _trace_event(mode: str, event_name: str, **extra: Any) -> dict[str, Any]:
    payload = {
        "event": event_name,
        "source": "lambda",
        "integration_version": INTEGRATION_VERSION,
    }
    payload.update({k: v for k, v in extra.items() if v is not None})
    connect_id = payload.get("connect_id") or payload.get("contact_id")
    if connect_id:
        payload["connect_id"] = connect_id
    return payload


def _publish_trace(
    mode: str,
    event_name: str,
    xray_trace_id: str | None = None,
    **extra: Any,
) -> None:
    try:
        url = (
            f"{SIERRA_API_BASE}/packages/{AGENT_TOKEN}/trace"
            f"?module_id={quote(_trace_module_id(mode), safe='')}"
        )
        body = json.dumps(_trace_event(mode, event_name, **extra)).encode("utf-8")
        response = _http.request(
            "POST",
            url,
            headers=_auth_headers(xray_trace_id, "application/json", mode=mode),
            body=body,
        )
        logger.info("_publish_trace: %s status=%d", event_name, response.status)
    except Exception as e:
        logger.warning("_publish_trace failed: %s %s", event_name, e)


def _json_object(raw: Any) -> dict[str, Any]:
    if isinstance(raw, dict):
        return raw
    if not isinstance(raw, str):
        return {}
    value = raw.strip()
    if not value or value.startswith("$."):
        return {}
    try:
        parsed = json.loads(value)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def _coerce_transfer_value(raw: Any) -> Any:
    if not isinstance(raw, str):
        return raw
    value = raw.strip()
    if not value or value.startswith("$."):
        return None
    if value[0] in ("{", "["):
        try:
            return json.loads(value)
        except Exception:
            return raw
    return raw


def _custom_transfer_data(parameters: dict[str, Any]) -> dict[str, Any]:
    transfer_data: dict[str, Any] = {}
    for key in (
        "transferData",
        "transfer_data",
        "transferDataAttributes",
        "sierraTransferData",
        "sierraInboundTransferData",
    ):
        transfer_data.update(_json_object(parameters.get(key)))

    prefixes = ("transferData.", "transfer_data.", "sierraTransferData.")
    for key, value in parameters.items():
        for prefix in prefixes:
            if key.startswith(prefix) and len(key) > len(prefix):
                coerced = _coerce_transfer_value(value)
                if coerced is not None:
                    transfer_data[key[len(prefix) :]] = coerced
                break
    return transfer_data


def _merge_common_transfer_data(
    base: dict[str, Any],
    parameters: dict[str, Any],
    run_id_keys: tuple[str, ...],
) -> dict[str, Any]:
    test_mode = (
        str(parameters.get("sierraTestMode") or parameters.get("test_mode") or "").strip().lower()
    )
    if test_mode in ("1", "true", "yes", "diagnostic", "debug"):
        base["sierraVoiceTestMode"] = test_mode

    for key in ("run_id",) + run_id_keys:
        run_id = str(parameters.get(key) or "").strip()
        if run_id:
            base[key] = run_id
            break

    base.update(_custom_transfer_data(parameters))
    return base


def _pstn_transfer_data(contact_id: str, parameters: dict[str, Any]) -> dict[str, Any]:
    return _merge_common_transfer_data(
        {"contactId": contact_id},
        parameters,
        ("connect_pstn_e2e_run_id",),
    )


def _evt_transfer_data(
    contact_id: str,
    from_addr: str,
    to_addr: str,
    parameters: dict[str, Any],
) -> dict[str, Any]:
    data: dict[str, Any] = {"uuiSessionId": contact_id, "source": "amazon_connect_evt"}
    if from_addr:
        data["fromPhoneNumber"] = from_addr
    if to_addr:
        data["toPhoneNumber"] = to_addr
    return _merge_common_transfer_data(data, parameters, ("connect_evt_e2e_run_id",))


def _request_transfer_data_keys(
    mode: str,
    body: dict[str, Any],
    xray_trace_id: str | None = None,
    telemetry_events: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    logger.info(
        "request_transfer_data_keys: mode=%s payload_keys=%s transfer_data_keys=%s",
        mode,
        sorted(body.keys()),
        sorted((body.get("transfer_data") or {}).keys()),
    )
    try:
        response = _http.request(
            "POST",
            TRANSFER_DATA_API_KEYS_URL,
            headers=_auth_headers(
                xray_trace_id,
                "application/json",
                telemetry_events=telemetry_events,
                mode=mode,
            ),
            body=json.dumps(body).encode("utf-8"),
        )
        response_body = response.data.decode("utf-8")
        logger.info(
            "request_transfer_data_keys: status=%d response_bytes=%d",
            response.status,
            len(response_body),
        )
        if response.status >= 400:
            return _failure(
                f"API returned status {response.status}: {response_body}",
                ERROR_TRANSFER_DATA_API,
                response.status,
                telemetry_accepted=_telemetry_accepted(response),
            )
        try:
            data = json.loads(response_body)
        except Exception as e:
            return _failure(
                f"Failed to parse transfer data key response: {e}",
                ERROR_TRANSFER_DATA_PARSE,
                telemetry_accepted=_telemetry_accepted(response),
            )
        inbound_key = str(data.get("inbound_key") or "")
        outbound_key = str(data.get("outbound_key") or "")
        if not inbound_key or not outbound_key:
            return _failure(
                "Transfer Data API response did not include keys",
                ERROR_TRANSFER_DATA_PARSE,
                telemetry_accepted=_telemetry_accepted(response),
            )
        result = {
            "success": True,
            "inbound_key": inbound_key,
            "outbound_key": outbound_key,
            "telemetry_accepted": _telemetry_accepted(response),
        }
        result.update(data)
        return result
    except Exception as e:
        logger.exception("request_transfer_data_keys: exception")
        return _failure(str(e), ERROR_TRANSFER_DATA_EXCEPTION)


def _retry_after_seconds(value: Any, default: float = 1.0) -> float:
    try:
        seconds = float(str(value).strip())
    except (TypeError, ValueError):
        return default
    return min(max(seconds, 0.1), 2.0)


def _load_outbound_data(
    mode: str,
    outbound_key: str,
    xray_trace_id: str | None = None,
    telemetry_events: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    url = (
        f"{TRANSFER_DATA_API_URL}?key={quote(outbound_key, safe='')}"
        f"&compatibility_date={TRANSFER_DATA_COMPATIBILITY_DATE}"
    )
    deadline = time.monotonic() + OUTBOUND_DATA_POLL_BUDGET_SECONDS
    while True:
        try:
            response = _http.request(
                "GET",
                url,
                headers=_auth_headers(
                    xray_trace_id,
                    telemetry_events=telemetry_events,
                    mode=mode,
                ),
            )
            response_body = response.data.decode("utf-8")
        except Exception as e:
            logger.exception("load_outbound_data: exception")
            return _failure(str(e), ERROR_TRANSFER_DATA_EXCEPTION)

        logger.info(
            "load_outbound_data: mode=%s status=%d response_bytes=%d",
            mode,
            response.status,
            len(response_body),
        )
        if response.status == 200:
            try:
                data = json.loads(response_body)
            except Exception as e:
                return _failure(
                    f"Failed to parse transfer data response: {e}",
                    ERROR_TRANSFER_DATA_PARSE,
                    telemetry_accepted=_telemetry_accepted(response),
                )
            return {
                "success": True,
                "data": data,
                "telemetry_accepted": _telemetry_accepted(response),
            }
        if response.status == 410:
            if mode == "evt":
                return {
                    "success": True,
                    "data": {},
                    "telemetry_accepted": _telemetry_accepted(response),
                }
            return _failure(
                "Agent completed without writing transfer data",
                ERROR_TRANSFER_DATA_NOT_PRODUCED,
                response.status,
                telemetry_accepted=_telemetry_accepted(response),
            )
        if response.status == 425:
            if time.monotonic() < deadline:
                time.sleep(_retry_after_seconds(response.headers.get("Retry-After")))
                continue
            if "agent has not started" in response_body:
                error_code = ERROR_TRANSFER_DATA_AGENT_NOT_STARTED
            elif "agent in progress" in response_body:
                error_code = ERROR_TRANSFER_DATA_AGENT_IN_PROGRESS
            else:
                error_code = ERROR_TRANSFER_DATA_NOT_READY
            return _failure(
                response_body.strip() or "Transfer data not ready",
                error_code,
                response.status,
                telemetry_accepted=_telemetry_accepted(response),
            )
        if response.status == 404:
            return _failure(
                "No outbound transfer data found for this contact",
                ERROR_TRANSFER_DATA_NOT_FOUND,
                response.status,
                telemetry_accepted=_telemetry_accepted(response),
            )
        return _failure(
            f"API returned status {response.status}: {response_body}",
            ERROR_TRANSFER_DATA_API,
            response.status,
            telemetry_accepted=_telemetry_accepted(response),
        )


def _safe_sip_user(value: Any, fallback: str) -> str:
    text = str(value or "").strip()
    if text.startswith("+"):
        return text
    text = re.sub(r"[^A-Za-z0-9_.!~*'()+-]", "", text)
    return text or fallback


def _connect_string(value: Any) -> str:
    if isinstance(value, bool):
        return "true" if value else "false"
    if value is None:
        return ""
    if isinstance(value, (dict, list)):
        return json.dumps(value, separators=(",", ":"))
    return str(value)


def _connect_transfer_data_response(data: Any) -> dict[str, str]:
    payload = dict(data) if isinstance(data, dict) else {}
    if "shouldDisconnect" not in payload:
        payload["shouldDisconnect"] = True
    transfer_data_json = json.dumps(payload, separators=(",", ":"))
    response = {
        "success": "true",
        "data": transfer_data_json,
        "transferData": transfer_data_json,
    }
    for key, value in payload.items():
        response_key = str(key)
        if response_key in response:
            continue
        response[response_key] = _connect_string(value)
    return response


def _transfer_to_agent(
    mode: str,
    contact_id: str,
    contact_data: dict[str, Any],
    parameters: dict[str, Any],
    xray_trace_id: str | None = None,
    telemetry_events: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    customer_endpoint = contact_data.get("CustomerEndpoint", {})
    system_endpoint = contact_data.get("SystemEndpoint", {})
    from_addr = customer_endpoint.get("Address", "") or ""
    to_addr = system_endpoint.get("Address", "") or ""

    if mode == "evt":
        transfer_data = _evt_transfer_data(contact_id, from_addr, to_addr, parameters)
        voice_connector_arn = str(
            parameters.get("VoiceConnectorArn") or SIERRA_VOICE_CONNECTOR_ARN
        ).strip()
        if not voice_connector_arn:
            return _failure(
                "Missing VoiceConnectorArn or SIERRA_VOICE_CONNECTOR_ARN for EVT transfer mode",
                ERROR_MISSING_CONFIGURATION,
            )
        body = {
            "method": "uui_session_id",
            "uuiSessionId": contact_id,
            "ttl": str(_ttl_seconds(mode)),
            "transfer_data": transfer_data,
        }
        key_result = _request_transfer_data_keys(mode, body, xray_trace_id, telemetry_events)
        if not key_result["success"]:
            return key_result
        to_user = str(parameters.get("ToUser") or SIERRA_SIP_USERNAME).strip()
        from_user = _safe_sip_user(
            parameters.get("FromUser") or SIERRA_SIP_FROM_USER or from_addr,
            "amazon-connect",
        )
        return {
            "success": True,
            "transferMode": "evt",
