def _checkpoint(
    name: str,
    title: str,
    status: str,
    latency_ms: int = 0,
    error: str | None = None,
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "name": name,
        "title": title,
        "status": status,
        "latency_ms": latency_ms,
        "error": error,
        "metadata": metadata or {},
        "timestamp": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
    }


def _diagnostic_transfer_data_checkpoint(mode: str, xray_trace_id: str) -> dict[str, Any]:
    start = time.time()
    if mode == "evt":
        session_id = f"diagnostic-{int(time.time())}"
        body = {
            "method": "uui_session_id",
            "uuiSessionId": session_id,
            "ttl": str(_ttl_seconds(mode)),
            "transfer_data": {
                "diagnostic": True,
                "uuiSessionId": session_id,
                "source": "amazon_connect_evt",
                "trace_id": xray_trace_id,
            },
        }
    else:
        body = {
            "from_number": "+10000000000",
            "to_number": SIERRA_PHONE_NUMBER or "+10000000001",
            "ttl": str(_ttl_seconds(mode)),
            "transfer_data": {"diagnostic": True, "trace_id": xray_trace_id},
        }

    result = _request_transfer_data_keys(mode, body, xray_trace_id)
    latency_ms = int((time.time() - start) * 1000)
    if not result["success"]:
        return _checkpoint(
            "transfer_data_inbound",
            "Transfer Data endpoint called",
            "fail",
            latency_ms=latency_ms,
            error=str(result.get("error") or "Transfer Data API check failed"),
        )

    metadata = {
        "inbound_key": result.get("inbound_key", ""),
        "outbound_key": result.get("outbound_key", ""),
    }
    if result.get("dtmf"):
        metadata["dtmf"] = result.get("dtmf")
    target_phone = result.get("target_phone_number") or result.get("targetPhoneNumber")
    if target_phone:
        metadata["target_phone_number"] = target_phone
    return _checkpoint(
        "transfer_data_inbound",
        "Transfer Data endpoint called",
        "pass",
        latency_ms=latency_ms,
        metadata=metadata,
    )


def run_diagnostic(context: Any = None) -> dict[str, Any]:
    xray = os.environ.get("_X_AMZN_TRACE_ID", f"Root=1-{int(time.time()):08x}-diagnostic")
    mode = _mode({})
    transfer_cp = _diagnostic_transfer_data_checkpoint(mode, xray)
    checkpoints = [
        _checkpoint("amazon_connect_flow", "AWS Amazon Connect flow", "skip"),
        _checkpoint(
            "lambda_installed",
            "Lambda installed",
            "pass",
            metadata={
                "lambda_arn": (
                    getattr(context, "invoked_function_arn", "unknown") if context else "local"
                ),
                "shared_lambda": True,
                "mode": mode,
            },
        ),
        _checkpoint("contact_flow_installed", "Flow installed", "skip"),
        _checkpoint(
            "api_access_verified",
            "API access verified",
            "pass" if transfer_cp["status"] == "pass" else "fail",
            error=transfer_cp.get("error"),
        ),
        _checkpoint("call_started", "Call started", "skip"),
        transfer_cp,
        _checkpoint(
            "pstn_transfer" if mode == "pstn" else "evt_transfer",
            "PSTN transfer" if mode == "pstn" else "EVT transfer",
            "skip",
            metadata={"reason": "Requires a live Amazon Connect call"},
        ),
        _checkpoint("call_connected_sierra", "Call connected to Sierra", "skip"),
        _checkpoint("end_call", "End call", "skip"),
        _checkpoint("transfer_data_outbound", "Transfer Data endpoint called", "skip"),
        _checkpoint("transfer_complete", "Transfer complete", "skip"),
    ]
    passed = sum(1 for cp in checkpoints if cp["status"] == "pass")
    failed = sum(1 for cp in checkpoints if cp["status"] == "fail")
    skipped = sum(1 for cp in checkpoints if cp["status"] == "skip")
    return {
        "version": "1",
        "xray_trace_id": xray,
        "timestamp": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        "checkpoints": checkpoints,
        "summary": {
            "total": len(checkpoints),
            "passed": passed,
            "failed": failed,
            "skipped": skipped,
        },
    }


