        logger.info(
            "lambda_handler: mode=%s operation=%s contact_id=%s", mode, operation, contact_id
        )

        if operation == "run_diagnostic" or event.get("action") == "run_diagnostic":
            publish_lambda_invoked_once()
            return run_diagnostic(context)

        if not contact_id:
            result = _failure("Missing ContactId", ERROR_MISSING_CONTACT_ID)
            publish_lambda_invoked_once()
            _publish_trace(
                mode,
                "lambda_failed",
                xray,
                operation=operation,
                error=result["error"],
                error_code=result["error_code"],
            )
            return _connect_failure_response(result)

        lambda_invoked_event = _trace_event(
            mode,
            "lambda_invoked",
            operation=operation,
            contact_id=contact_id,
        )

        if operation == "transfer_to_agent":
            start_event = _trace_event(
                mode,
                "transfer_to_agent_start",
                contact_id=contact_id,
                from_number=from_addr or None,
            )
            result = _transfer_to_agent(
                mode,
                contact_id,
                contact_data,
                parameters,
                xray,
                telemetry_events=[lambda_invoked_event, start_event],
            )
            if result.get("telemetry_accepted"):
                lambda_invoked_published = True
            else:
                publish_lambda_invoked_once()
                _publish_trace(
                    mode,
                    "transfer_to_agent_start",
                    xray,
                    contact_id=contact_id,
                    from_number=from_addr or None,
                )
            if not result["success"]:
                _publish_trace(
                    mode,
                    "transfer_to_agent_failed",
                    xray,
                    contact_id=contact_id,
                    error=result.get("error"),
                    error_code=result.get("error_code"),
                    status_code=result.get("status_code"),
                )
                return _connect_failure_response(result)
            response = {k: v for k, v in result.items() if k != "telemetry_accepted"}
            response["success"] = "true"
            _publish_trace(mode, "transfer_to_agent_success", xray, contact_id=contact_id)
            logger.info("transfer_to_agent response prepared")
            return response

        if operation == "transfer_from_agent":
            outbound_key = str(parameters.get("outboundKey", "")).strip()
            if not outbound_key:
                result = _failure("Missing outboundKey", ERROR_MISSING_OUTBOUND_KEY)
                publish_lambda_invoked_once()
                _publish_trace(
                    mode,
                    "transfer_from_agent_failed",
                    xray,
                    contact_id=contact_id,
                    error=result.get("error"),
                    error_code=result.get("error_code"),
                )
                return _connect_failure_response(result)

            start_event = _trace_event(
                mode,
                "transfer_from_agent_start",
                contact_id=contact_id,
                outbound_key=outbound_key,
            )
            result = _load_outbound_data(
                mode,
                outbound_key,
                xray,
                telemetry_events=[lambda_invoked_event, start_event],
            )
            if result.get("telemetry_accepted"):
                lambda_invoked_published = True
            else:
                publish_lambda_invoked_once()
                _publish_trace(
                    mode,
                    "transfer_from_agent_start",
                    xray,
                    contact_id=contact_id,
                    outbound_key=outbound_key,
                )
            if not result["success"]:
                _publish_trace(
                    mode,
                    "transfer_from_agent_failed",
                    xray,
                    contact_id=contact_id,
                    error=result.get("error"),
                    error_code=result.get("error_code"),
                    status_code=result.get("status_code"),
                )
                return _connect_failure_response(result)

            data = result.get("data", {})
            response = _connect_transfer_data_response(data)
            _publish_trace(
                mode,
                "transfer_from_agent_success",
                xray,
                contact_id=contact_id,
                shouldDisconnect=response.get("shouldDisconnect"),
            )
            logger.info("transfer_from_agent response: %s", json.dumps(response, default=str)[:500])
            return response

        result = _failure(f"Unknown operation: {operation}", ERROR_UNKNOWN_OPERATION)
        publish_lambda_invoked_once()
        _publish_trace(
            mode,
            "lambda_failed",
            xray,
            operation=operation,
            contact_id=contact_id,
            error=result["error"],
            error_code=result["error_code"],
        )
        return _connect_failure_response(result)
    except Exception as e:
        logger.exception("lambda_handler: unhandled exception")
        result = _failure(f"Unhandled Lambda exception: {e}", ERROR_UNHANDLED_EXCEPTION)
        publish_lambda_invoked_once()
        _publish_trace(
            mode,
            "lambda_failed",
            xray,
            operation=operation,
            contact_id=contact_id,
            error=result["error"],
            error_code=result["error_code"],
        )
        return _connect_failure_response(result)

