    }
    return value;
}

function sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
}

function asString(value: Json): string {
    if (value === null || value === undefined) {
        return "";
    }
    if (typeof value === "string") {
        return value;
    }
    return String(value);
}

function mode(parameters: { [key: string]: Json } = {}): "evt" | "pstn" {
    const explicit = asString(parameters["sierraTransferMode"] || SIERRA_TRANSFER_MODE)
        .trim()
        .toLowerCase();
    if (["evt", "external_voice_transfer", "external-voice-transfer"].includes(explicit)) {
        return "evt";
    }
    if (["pstn", "phone"].includes(explicit)) {
        return "pstn";
