    if (xrayTraceId) {
        headers["X-Amzn-Trace-Id"] = xrayTraceId;
    }
    if (telemetryEvents && telemetryEvents.length > 0) {
        headers["X-Sierra-Telemetry-Module-Id"] = traceModuleId(currentMode);
        headers["X-Sierra-Telemetry-Events"] = JSON.stringify(telemetryEvents);
