interface Result extends JsonObject {
    success: boolean;
}

function failure(
    error: string,
    errorCode: string,
    statusCode?: number,
    telemetryAccepted = false
): Result {
    const result: Result = { success: false, error, error_code: errorCode };
    if (statusCode !== undefined) {
        result["status_code"] = statusCode;
    }
    if (telemetryAccepted) {
        result["telemetry_accepted"] = true;
    }
    return result;
}

function connectFailureResponse(result: JsonObject): { [key: string]: string } {
    const response: { [key: string]: string } = {
        success: "false",
        error: asString(result["error"]),
        errorCode: asString(result["error_code"]),
    };
    if (result["status_code"] !== undefined && result["status_code"] !== null) {
        response["statusCode"] = asString(result["status_code"]);
    }
    return response;
}

function telemetryAccepted(response: Response): boolean {
    return (response.headers.get("X-Sierra-Telemetry-Accepted") || "").toLowerCase() === "true";
}

function traceEvent(eventName: string, extra: JsonObject = {}): JsonObject {
    const payload: JsonObject = {
        event: eventName,
        source: "lambda-ts",
        integration_version: INTEGRATION_VERSION,
    };
    for (const [key, value] of Object.entries(extra)) {
        if (value !== null && value !== undefined) {
            payload[key] = value;
        }
    }
    const connectId = payload["connect_id"] || payload["contact_id"];
    if (connectId) {
        payload["connect_id"] = connectId;
    }
    return payload;
}

async function publishTrace(
    currentMode: string,
    eventName: string,
    xrayTraceId?: string,
    extra: JsonObject = {}
): Promise<void> {
    try {
        const url =
            `${SIERRA_API_BASE}/packages/${AGENT_TOKEN}/trace` +
            `?module_id=${encodeURIComponent(traceModuleId(currentMode))}`;
        const response = await fetch(url, {
            method: "POST",
            headers: authHeaders({
                xrayTraceId,
                contentType: "application/json",
                mode: currentMode,
            }),
            body: JSON.stringify(traceEvent(eventName, extra)),
        });
        console.info(`publishTrace: ${eventName} status=${response.status}`);
    } catch (e) {
        console.warn(`publishTrace failed: ${eventName} ${String(e)}`);
    }
