    Object.assign(base, customTransferData(parameters));
    return base;
}

function pstnTransferData(contactId: string, parameters: { [key: string]: Json }): JsonObject {
    return mergeCommonTransferData({ contactId }, parameters, ["connect_pstn_e2e_run_id"]);
}

function evtTransferData(
    contactId: string,
    fromAddr: string,
    toAddr: string,
    parameters: { [key: string]: Json }
): JsonObject {
    const data: JsonObject = { uuiSessionId: contactId, source: "amazon_connect_evt" };
    if (fromAddr) {
        data["fromPhoneNumber"] = fromAddr;
    }
    if (toAddr) {
        data["toPhoneNumber"] = toAddr;
    }
    return mergeCommonTransferData(data, parameters, ["connect_evt_e2e_run_id"]);
