async function requestTransferDataKeys(
    currentMode: string,
    body: JsonObject,
    xrayTraceId?: string,
    telemetryEvents?: JsonObject[]
): Promise<Result> {
    const transferData = (body["transfer_data"] as JsonObject) || {};
    console.info(
        `requestTransferDataKeys: mode=${currentMode} payload_keys=${Object.keys(body).sort()} ` +
            `transfer_data_keys=${Object.keys(transferData).sort()}`
    );
    try {
        const response = await fetch(TRANSFER_DATA_API_KEYS_URL, {
            method: "POST",
            headers: authHeaders({
                xrayTraceId,
                contentType: "application/json",
                telemetryEvents,
                mode: currentMode,
            }),
            body: JSON.stringify(body),
        });
        const responseBody = await response.text();
        console.info(
            `requestTransferDataKeys: status=${response.status} response_bytes=${responseBody.length}`
        );
        if (response.status >= 400) {
            return failure(
                `API returned status ${response.status}: ${responseBody}`,
                ERROR_TRANSFER_DATA_API,
                response.status,
                telemetryAccepted(response)
            );
        }
        let data: JsonObject;
        try {
            data = JSON.parse(responseBody) as JsonObject;
        } catch (e) {
            return failure(
                `Failed to parse transfer data key response: ${String(e)}`,
                ERROR_TRANSFER_DATA_PARSE,
                undefined,
                telemetryAccepted(response)
            );
        }
        const inboundKey = asString(data["inbound_key"]);
        const outboundKey = asString(data["outbound_key"]);
        if (!inboundKey || !outboundKey) {
            return failure(
                "Transfer Data API response did not include keys",
                ERROR_TRANSFER_DATA_PARSE,
                undefined,
                telemetryAccepted(response)
            );
        }
        const result: Result = {
            success: true,
            inbound_key: inboundKey,
            outbound_key: outboundKey,
            telemetry_accepted: telemetryAccepted(response),
        };
        Object.assign(result, data);
        return result;
    } catch (e) {
        console.error(`requestTransferDataKeys: exception ${String(e)}`);
        return failure(String(e), ERROR_TRANSFER_DATA_EXCEPTION);
    }
}

function retryAfterMs(value: string | null, defaultMs = 1000): number {
    const seconds = Number.parseFloat((value || "").trim());
    if (!Number.isFinite(seconds)) {
        return defaultMs;
    }
    return Math.min(Math.max(seconds, 0.1), 2.0) * 1000;
}

async function loadOutboundData(
    currentMode: string,
    outboundKey: string,
    xrayTraceId?: string,
    telemetryEvents?: JsonObject[]
): Promise<Result> {
    const url =
        `${TRANSFER_DATA_API_URL}?key=${encodeURIComponent(outboundKey)}` +
        `&compatibility_date=${TRANSFER_DATA_COMPATIBILITY_DATE}`;
    const deadline = Date.now() + OUTBOUND_DATA_POLL_BUDGET_MS;
    for (;;) {
        let response: Response;
        let responseBody: string;
        try {
            response = await fetch(url, {
                method: "GET",
                headers: authHeaders({ xrayTraceId, telemetryEvents, mode: currentMode }),
            });
            responseBody = await response.text();
        } catch (e) {
            console.error(`loadOutboundData: exception ${String(e)}`);
            return failure(String(e), ERROR_TRANSFER_DATA_EXCEPTION);
        }

        console.info(
            `loadOutboundData: mode=${currentMode} status=${response.status} ` +
                `response_bytes=${responseBody.length}`
        );
        if (response.status === 200) {
            try {
                return {
                    success: true,
                    data: JSON.parse(responseBody),
                    telemetry_accepted: telemetryAccepted(response),
                };
            } catch (e) {
                return failure(
                    `Failed to parse transfer data response: ${String(e)}`,
                    ERROR_TRANSFER_DATA_PARSE,
                    undefined,
                    telemetryAccepted(response)
                );
            }
        }
        if (response.status === 410) {
            if (currentMode === "evt") {
                return { success: true, data: {}, telemetry_accepted: telemetryAccepted(response) };
            }
            return failure(
                "Agent completed without writing transfer data",
                ERROR_TRANSFER_DATA_NOT_PRODUCED,
                response.status,
                telemetryAccepted(response)
            );
        }
        if (response.status === 425) {
            if (Date.now() < deadline) {
                await sleep(retryAfterMs(response.headers.get("Retry-After")));
                continue;
            }
            let errorCode: string;
            if (responseBody.includes("agent has not started")) {
                errorCode = ERROR_TRANSFER_DATA_AGENT_NOT_STARTED;
            } else if (responseBody.includes("agent in progress")) {
                errorCode = ERROR_TRANSFER_DATA_AGENT_IN_PROGRESS;
            } else {
                errorCode = ERROR_TRANSFER_DATA_NOT_READY;
            }
            return failure(
                responseBody.trim() || "Transfer data not ready",
                errorCode,
                response.status,
                telemetryAccepted(response)
            );
        }
        if (response.status === 404) {
            return failure(
                "No outbound transfer data found for this contact",
                ERROR_TRANSFER_DATA_NOT_FOUND,
                response.status,
                telemetryAccepted(response)
            );
        }
        return failure(
            `API returned status ${response.status}: ${responseBody}`,
            ERROR_TRANSFER_DATA_API,
            response.status,
            telemetryAccepted(response)
        );
    }
}

function safeSipUser(value: Json, fallback: string): string {
    let text = asString(value).trim();
    if (text.startsWith("+")) {
        return text;
    }
    text = text.replace(/[^A-Za-z0-9_.!~*'()+-]/g, "");
    return text || fallback;
}

function connectString(value: Json): string {
    if (typeof value === "boolean") {
        return value ? "true" : "false";
    }
    if (value === null || value === undefined) {
        return "";
    }
    if (typeof value === "object") {
        return JSON.stringify(value);
    }
    return String(value);
}

function connectTransferDataResponse(data: Json): { [key: string]: string } {
    const payload: JsonObject =
        data && typeof data === "object" && !Array.isArray(data) ? { ...(data as JsonObject) } : {};
    if (!("shouldDisconnect" in payload)) {
        payload["shouldDisconnect"] = true;
    }
    const transferDataJson = JSON.stringify(payload);
    const response: { [key: string]: string } = {
        success: "true",
        data: transferDataJson,
        transferData: transferDataJson,
    };
    for (const [key, value] of Object.entries(payload)) {
        if (key in response) {
            continue;
        }
        response[key] = connectString(value);
    }
    return response;
}

async function transferToAgent(
    currentMode: string,
    contactId: string,
    contactData: ConnectContactData,
    parameters: { [key: string]: Json },
    xrayTraceId?: string,
    telemetryEvents?: JsonObject[]
): Promise<Result> {
    const fromAddr = contactData.CustomerEndpoint?.Address || "";
    const toAddr = contactData.SystemEndpoint?.Address || "";

    if (currentMode === "evt") {
        const transferData = evtTransferData(contactId, fromAddr, toAddr, parameters);
        const voiceConnectorArn = asString(
            parameters["VoiceConnectorArn"] || SIERRA_VOICE_CONNECTOR_ARN
        ).trim();
        if (!voiceConnectorArn) {
            return failure(
                "Missing VoiceConnectorArn or SIERRA_VOICE_CONNECTOR_ARN for EVT transfer mode",
                ERROR_MISSING_CONFIGURATION
            );
        }
        const body: JsonObject = {
            method: "uui_session_id",
            uuiSessionId: contactId,
            ttl: String(ttlSeconds(currentMode)),
            transfer_data: transferData,
        };
        const keyResult = await requestTransferDataKeys(
            currentMode,
            body,
            xrayTraceId,
            telemetryEvents
        );
        if (!keyResult.success) {
            return keyResult;
        }
        const toUser = asString(parameters["ToUser"] || SIERRA_SIP_USERNAME).trim();
        const fromUser = safeSipUser(
            parameters["FromUser"] || SIERRA_SIP_FROM_USER || fromAddr,
            "amazon-connect"
        );
        return {
            success: true,
            transferMode: "evt",
            inboundKey: asString(keyResult["inbound_key"]),
            outboundKey: asString(keyResult["outbound_key"]),
            voiceConnectorArn,
            toUser,
            fromUser,
            // Chime Voice Connector hex-encodes UserToUserInformation onto the SIP
            // User-to-User header (RFC 7433 ;encoding=hex), so pass plaintext and let
            // it apply the single canonical encode. Pre-hex-encoding here caused the
            // value to arrive double hex-encoded, so Sierra's parser couldn't extract
            // UUI_SESSION_ID. See Pinewood session pinewood-v2-chat-01kve0fm0yyax6cmswfjkz5dc8.
            userToUserInformation: `UUI_SESSION_ID=${contactId}`,
            transferData: JSON.stringify(transferData),
            telemetry_accepted: keyResult["telemetry_accepted"] || false,
        };
    }

    const sierraNumber = asString(parameters["SierraNumber"] || SIERRA_PHONE_NUMBER).trim();
    if (!sierraNumber) {
        return failure(
            "Missing SierraNumber or SIERRA_PHONE_NUMBER for PSTN transfer mode",
            ERROR_MISSING_CONFIGURATION
        );
    }
    const transferData = pstnTransferData(contactId, parameters);
    const body: JsonObject = {
        from_number: fromAddr,
        to_number: sierraNumber,
        ttl: String(ttlSeconds(currentMode)),
        transfer_data: transferData,
    };
    const method = transferMethod(parameters);
    if (method) {
        body["method"] = method;
    }
    const keyResult = await requestTransferDataKeys(
        currentMode,
        body,
        xrayTraceId,
        telemetryEvents
    );
    if (!keyResult.success) {
        return keyResult;
    }
    const targetPhone =
        keyResult["target_phone_number"] || keyResult["targetPhoneNumber"] || sierraNumber;
    return {
        success: true,
        transferMode: "pstn",
        dtmfCode: asString(keyResult["dtmf"] || "NONE"),
        inboundKey: asString(keyResult["inbound_key"]),
        outboundKey: asString(keyResult["outbound_key"]),
        targetPhoneNumber: asString(targetPhone).trim(),
        transferData: JSON.stringify(transferData),
        telemetry_accepted: keyResult["telemetry_accepted"] || false,
    };
}

function checkpoint(
    name: string,
    title: string,
    status: string,
    options: { latencyMs?: number; error?: string | null; metadata?: JsonObject } = {}
): JsonObject {
    return {
        name,
        title,
        status,
        latency_ms: options.latencyMs ?? 0,
        error: options.error ?? null,
        metadata: options.metadata ?? {},
        timestamp: new Date().toISOString().replace(/\.\d{3}Z$/, "Z"),
    };
}

async function diagnosticTransferDataCheckpoint(
    currentMode: string,
    xrayTraceId: string
): Promise<JsonObject> {
    const start = Date.now();
    let body: JsonObject;
    if (currentMode === "evt") {
        const sessionId = `diagnostic-${Math.floor(Date.now() / 1000)}`;
        body = {
            method: "uui_session_id",
            uuiSessionId: sessionId,
            ttl: String(ttlSeconds(currentMode)),
            transfer_data: {
                diagnostic: true,
                uuiSessionId: sessionId,
                source: "amazon_connect_evt",
                trace_id: xrayTraceId,
            },
        };
    } else {
        body = {
            from_number: "+10000000000",
            to_number: SIERRA_PHONE_NUMBER || "+10000000001",
            ttl: String(ttlSeconds(currentMode)),
            transfer_data: { diagnostic: true, trace_id: xrayTraceId },
        };
    }

    const result = await requestTransferDataKeys(currentMode, body, xrayTraceId);
    const latencyMs = Date.now() - start;
    if (!result.success) {
        return checkpoint("transfer_data_inbound", "Transfer Data endpoint called", "fail", {
            latencyMs,
            error: asString(result["error"]) || "Transfer Data API check failed",
        });
    }

    const metadata: JsonObject = {
        inbound_key: asString(result["inbound_key"]),
        outbound_key: asString(result["outbound_key"]),
    };
    if (result["dtmf"]) {
        metadata["dtmf"] = result["dtmf"];
    }
    const targetPhone = result["target_phone_number"] || result["targetPhoneNumber"];
    if (targetPhone) {
        metadata["target_phone_number"] = targetPhone;
    }
    return checkpoint("transfer_data_inbound", "Transfer Data endpoint called", "pass", {
        latencyMs,
        metadata,
    });
}

async function runDiagnostic(context?: LambdaContext): Promise<JsonObject> {
    const xray =
        env._X_AMZN_TRACE_ID ||
        `Root=1-${Math.floor(Date.now() / 1000)
            .toString(16)
            .padStart(8, "0")}-diagnostic`;
    const currentMode = mode({});
    const transferCp = await diagnosticTransferDataCheckpoint(currentMode, xray);
    const checkpoints: JsonObject[] = [
        checkpoint("amazon_connect_flow", "AWS Amazon Connect flow", "skip"),
        checkpoint("lambda_installed", "Lambda installed", "pass", {
            metadata: {
                lambda_arn: context ? (context.invokedFunctionArn ?? "unknown") : "local",
                shared_lambda: true,
                mode: currentMode,
            },
        }),
        checkpoint("contact_flow_installed", "Flow installed", "skip"),
        checkpoint(
            "api_access_verified",
            "API access verified",
            transferCp["status"] === "pass" ? "pass" : "fail",
            { error: asString(transferCp["error"]) || null }
        ),
        checkpoint("call_started", "Call started", "skip"),
        transferCp,
        checkpoint(
            currentMode === "pstn" ? "pstn_transfer" : "evt_transfer",
            currentMode === "pstn" ? "PSTN transfer" : "EVT transfer",
            "skip",
            { metadata: { reason: "Requires a live Amazon Connect call" } }
        ),
        checkpoint("call_connected_sierra", "Call connected to Sierra", "skip"),
        checkpoint("end_call", "End call", "skip"),
        checkpoint("transfer_data_outbound", "Transfer Data endpoint called", "skip"),
        checkpoint("transfer_complete", "Transfer complete", "skip"),
    ];
    const passed = checkpoints.filter(cp => cp["status"] === "pass").length;
    const failed = checkpoints.filter(cp => cp["status"] === "fail").length;
    const skipped = checkpoints.filter(cp => cp["status"] === "skip").length;
    return {
        version: "1",
        xray_trace_id: xray,
        timestamp: new Date().toISOString().replace(/\.\d{3}Z$/, "Z"),
        checkpoints,
        summary: { total: checkpoints.length, passed, failed, skipped },
    };
}

export async function handler(
    event: ConnectEvent,
    context?: LambdaContext
): Promise<{ [key: string]: string } | JsonObject> {
    const xray = env._X_AMZN_TRACE_ID || "";
    let operation = "";
    let contactId = "";
    let currentMode = "pstn";
    let lambdaInvokedPublished = false;

    const publishLambdaInvokedOnce = async (): Promise<void> => {
        if (lambdaInvokedPublished) {
            return;
        }
        await publishTrace(currentMode, "lambda_invoked", xray, {
            operation,
            contact_id: contactId,
        });
        lambdaInvokedPublished = true;
    };

    try {
        console.info(`handler: event=${JSON.stringify(event).slice(0, 2000)}`);
        const contactData = event.Details?.ContactData ?? {};
        const parameters = (event.Details?.Parameters ?? {}) as { [key: string]: Json };
        operation = asString(
            "operation" in parameters ? parameters["operation"] : (event.action ?? "")
        );
        contactId = contactData.ContactId || "";
        const fromAddr = (contactData.CustomerEndpoint?.Address || "").trim();
        currentMode = mode(parameters);
        console.info(`handler: mode=${currentMode} operation=${operation} contact_id=${contactId}`);

        if (operation === "run_diagnostic" || event.action === "run_diagnostic") {
            await publishLambdaInvokedOnce();
            return await runDiagnostic(context);
        }

        if (!contactId) {
            const result = failure("Missing ContactId", ERROR_MISSING_CONTACT_ID);
            await publishLambdaInvokedOnce();
            await publishTrace(currentMode, "lambda_failed", xray, {
                operation,
                error: result["error"],
                error_code: result["error_code"],
            });
            return connectFailureResponse(result);
        }

        const lambdaInvokedEvent = traceEvent("lambda_invoked", {
            operation,
            contact_id: contactId,
        });

        if (operation === "transfer_to_agent") {
            const startEvent = traceEvent("transfer_to_agent_start", {
                contact_id: contactId,
                from_number: fromAddr || null,
            });
            const result = await transferToAgent(
                currentMode,
                contactId,
                contactData,
                parameters,
                xray,
                [lambdaInvokedEvent, startEvent]
            );
            if (result["telemetry_accepted"]) {
                lambdaInvokedPublished = true;
            } else {
                await publishLambdaInvokedOnce();
                await publishTrace(currentMode, "transfer_to_agent_start", xray, {
                    contact_id: contactId,
                    from_number: fromAddr || null,
                });
            }
            if (!result.success) {
                await publishTrace(currentMode, "transfer_to_agent_failed", xray, {
                    contact_id: contactId,
                    error: result["error"],
                    error_code: result["error_code"],
                    status_code: result["status_code"],
                });
                return connectFailureResponse(result);
            }
            const response: JsonObject = {};
            for (const [key, value] of Object.entries(result)) {
                if (key !== "telemetry_accepted") {
                    response[key] = value;
                }
            }
            response["success"] = "true";
            await publishTrace(currentMode, "transfer_to_agent_success", xray, {
                contact_id: contactId,
            });
            console.info("transfer_to_agent response prepared");
            return response;
        }

        if (operation === "transfer_from_agent") {
            const outboundKey = asString(parameters["outboundKey"]).trim();
            if (!outboundKey) {
                const result = failure("Missing outboundKey", ERROR_MISSING_OUTBOUND_KEY);
                await publishLambdaInvokedOnce();
                await publishTrace(currentMode, "transfer_from_agent_failed", xray, {
                    contact_id: contactId,
                    error: result["error"],
                    error_code: result["error_code"],
                });
                return connectFailureResponse(result);
            }

            const startEvent = traceEvent("transfer_from_agent_start", {
                contact_id: contactId,
                outbound_key: outboundKey,
            });
            const result = await loadOutboundData(currentMode, outboundKey, xray, [
                lambdaInvokedEvent,
                startEvent,
            ]);
            if (result["telemetry_accepted"]) {
                lambdaInvokedPublished = true;
            } else {
                await publishLambdaInvokedOnce();
                await publishTrace(currentMode, "transfer_from_agent_start", xray, {
                    contact_id: contactId,
                    outbound_key: outboundKey,
                });
            }
            if (!result.success) {
                await publishTrace(currentMode, "transfer_from_agent_failed", xray, {
                    contact_id: contactId,
                    error: result["error"],
                    error_code: result["error_code"],
                    status_code: result["status_code"],
                });
                return connectFailureResponse(result);
            }

            const response = connectTransferDataResponse(result["data"]);
            await publishTrace(currentMode, "transfer_from_agent_success", xray, {
                contact_id: contactId,
                shouldDisconnect: response["shouldDisconnect"],
            });
            console.info(`transfer_from_agent response: ${JSON.stringify(response).slice(0, 500)}`);
            return response;
        }

        const result = failure(`Unknown operation: ${operation}`, ERROR_UNKNOWN_OPERATION);
        await publishLambdaInvokedOnce();
        await publishTrace(currentMode, "lambda_failed", xray, {
            operation,
            contact_id: contactId,
            error: result["error"],
            error_code: result["error_code"],
        });
        return connectFailureResponse(result);
    } catch (e) {
        console.error(`handler: unhandled exception ${String(e)}`);
        const result = failure(
            `Unhandled Lambda exception: ${String(e)}`,
            ERROR_UNHANDLED_EXCEPTION
        );
        await publishLambdaInvokedOnce();
        await publishTrace(currentMode, "lambda_failed", xray, {
            operation,
            contact_id: contactId,
            error: result["error"],
            error_code: result["error_code"],
        });
        return connectFailureResponse(result);
    }
}

