// Copyright Sierra
//
// Build/packaging helper for the Sierra Amazon Connect Lambda (TypeScript). It
// bundles sierra-connect-lambda.ts into a Node.js Lambda artifact with esbuild.
//
// Deployment to AWS (Lambda function + IAM execution role + Amazon Connect
// association, voice connector, contact flows, ...) is handled by the shared
// Python setup utility, which treats the Lambda language as the only variable:
//
//   python ../amazon-connect-setup.py --apply --lambda-runtime typescript
//
// That utility shells out to `node deploy-lambda.mjs --build-only` to produce
// the esbuild bundle, then zips and deploys it.
//
// Usage:
//   npm install
//   node deploy-lambda.mjs               # build dist/index.js + package dist/lambda.zip
//   node deploy-lambda.mjs --build-only  # build dist/index.js only (used by the Python setup script)

import { mkdirSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
const ENTRY_FILE = path.join(SCRIPT_DIR, "sierra-connect-lambda.ts");
const TSCONFIG_FILE = path.join(SCRIPT_DIR, "tsconfig.json");
const DIST_DIR = path.join(SCRIPT_DIR, "dist");
const BUNDLE_FILE = path.join(DIST_DIR, "index.js");
const ZIP_FILE = path.join(DIST_DIR, "lambda.zip");

async function buildBundle() {
    const esbuild = await import("esbuild");
    mkdirSync(DIST_DIR, { recursive: true });
    await esbuild.build({
        entryPoints: [ENTRY_FILE],
        bundle: true,
        platform: "node",
        target: "node20",
        format: "cjs",
        outfile: BUNDLE_FILE,
        tsconfig: TSCONFIG_FILE,
        logLevel: "info",
    });
    console.log(`  OK: Bundled Lambda to ${BUNDLE_FILE}`);
}

async function packageZip() {
    const AdmZip = (await import("adm-zip")).default;
    const zip = new AdmZip();
    zip.addLocalFile(BUNDLE_FILE);
    zip.writeZip(ZIP_FILE);
    console.log(`  OK: Wrote deployment package ${ZIP_FILE}`);
}

async function main() {
    const buildOnly = process.argv.slice(2).includes("--build-only");

    console.log("Building Sierra Connect Lambda (TypeScript)...");
    await buildBundle();
    if (buildOnly) {
        return;
    }

    await packageZip();
    console.log("");
    console.log("Build complete. Deploy with the shared Python setup utility:");
    console.log("  python ../amazon-connect-setup.py --apply --lambda-runtime typescript");
    console.log("Or upload dist/lambda.zip manually (runtime nodejs20.x, handler index.handler).");
}

main().catch(err => {
    console.error(`  FAIL: ${err?.message ?? err}`);
    process.exit(1);
});

